$(function(){$.getJSON("../json_data/record.json",function(i){$.each(i,function(i,s){var a='<li class="time-axis-item"><div class="time-axis-date">'+s.date+'<span></span></div><div class="time-axis-title">'+s.title+'</div><p class="time-axis-achievement">'+s.achievement+"</p></li>";$(".time-axis").append(a)})})});